function renderGod(){document.getElementById('godDur').value=S.god.dur;if(S.god.active&&S.god.endsAt&&S.god.endsAt>Date.now()){document.getElementById('godBox').classList.add('on');document.getElementById('godBadge').textContent='Running';document.getElementById('godBadge').classList.remove('idle');document.getElementById('godBtn').textContent='Stop';updateGod()}else{S.god.active=false;document.getElementById('godBox').classList.remove('on');document.getElementById('godBadge').textContent='Off';document.getElementById('godBadge').classList.add('idle');document.getElementById('godBtn').textContent='Start';document.getElementById('godTimer').textContent='--:--:--'}updateRunBtn()}
