function parseCSV(txt){return txt.split(/\r?\n/).filter(l=>l.trim()).map(l=>l.split(',').map(c=>c.replace(/^"|"$/g,'').trim()))}
function onSheet(e){const f=e.target.files[0];if(!f)return;const rd=new FileReader();const ext=(f.name.split('.').pop()||'').toLowerCase();rd.onload=function(ev){try{let rows=[];if(ext==='csv'||ext==='txt'){rows=parseCSV(ev.target.result)}else{if(typeof XLSX==='undefined'){toast('Excel reader unavailable offline — save your sheet as CSV');return}const wb=XLSX.read(ev.target.result,{type:'binary'});const ws=wb.Sheets[wb.SheetNames[0]];rows=XLSX.utils.sheet_to_json(ws,{header:1})}ingestRows(rows)}catch(err){toast('Could not read file: '+err.message)}};if(ext==='csv'||ext==='txt'){rd.readAsText(f)}else{rd.readAsBinaryString(f)}e.target.value=''}
function ingestRows(rows){if(!rows||!rows.length){toast('That file looks empty');return}let hdr=rows[0].map(x=>String(x||'').toLowerCase().trim());let ei=hdr.findIndex(h=>h.indexOf('email')>=0||h.indexOf('mail')>=0);let ni=hdr.findIndex(h=>h.indexOf('name')>=0);let start=1;if(ei<0){ei=0;ni=hdr.length>1?1:-1;start=0}const out=[];for(let i=start;i<rows.length;i++){const row=rows[i]||[];const em=String(row[ei]||'').trim();if(em&&/.+@.+\..+/.test(em)){out.push({email:em,name:ni>=0?String(row[ni]||'').trim():''})}}if(!out.length){toast('No email addresses found in that file');return}S.recipients=out;save();updateRecipCount();renderOutbox();toast('Loaded '+out.length+' recipient(s)')}
function renderOutbox(){['obList','obList2'].forEach(cid=>{const c=document.getElementById(cid);if(!c)return;const isPage=(cid==='obList2');const items=S.outbox.filter(o=>o.status!=='skipped'&&(isPage||(o.status==='pending'&&!o.attempted)));if(!items.length){c.innerHTML='<div class="empty">'+(isPage?'Nothing here yet. Approved and sent mail will show up on this page.':'Nothing waiting for approval right now.')+'</div>';return}c.innerHTML='';if(isPage){const tb=document.createElement('div');tb.style.cssText='display:flex;justify-content:flex-end;gap:8px;margin-bottom:10px';const selCount=items.filter(o=>selOutbox.has(o.id)).length;const del=document.createElement('button');del.className='btn ghost sm';del.textContent='Delete selected'+(selCount?(' ('+selCount+')'):'');del.disabled=!selCount;del.onclick=()=>deleteSelectedOutbox();tb.appendChild(del);const hasCamp=items.some(o=>o.type==='email'&&(o.attempted||o.status==='sent')&&o.recipients&&o.recipients.length);if(hasCamp){const rab=document.createElement('button');rab.className='btn sm';rab.textContent='Resend all';rab.onclick=()=>resendAllCampaigns();tb.appendChild(rab)}c.appendChild(tb)}items.forEach(o=>{const tried=(o.attempted||o.status==='sent');const d=document.createElement('div');d.className='art';d.style.cursor='default';if(isPage){d.style.display='flex';d.style.alignItems='flex-start';d.style.gap='10px';const cb=document.createElement('input');cb.type='checkbox';cb.checked=selOutbox.has(o.id);cb.style.marginTop='4px';cb.onchange=()=>{if(cb.checked)selOutbox.add(o.id);else selOutbox.delete(o.id);renderOutbox()};d.appendChild(cb)}const inner=document.createElement('div');inner.style.flex='1';const b=document.createElement('span');b.className='kbadge';b.textContent=o.type==='email'?'Email':'X post';const ti=document.createElement('div');ti.className='atitle';ti.textContent=o.title;const pv=document.createElement('div');pv.style.cssText='font-size:12px;color:#9b958a;margin:4px 0 8px;white-space:pre-wrap;max-height:54px;overflow:hidden';pv.textContent=(o.type==='email'?('Subject: '+o.subject+NL):'')+o.body;inner.appendChild(b);inner.appendChild(ti);inner.appendChild(pv);const act=document.createElement('div');act.style.cssText='display:flex;gap:8px;flex-wrap:wrap';const mkBtn=(label,ghost,fn)=>{const x=document.createElement('button');x.className='btn '+(ghost?'ghost ':'')+'sm';x.textContent=label;x.onclick=fn;return x};if(o.status==='sending'){const s=document.createElement('span');s.className='kbadge';s.textContent='Sending...';act.appendChild(s)}else if(o.type==='email'){if(tried){const okN=o.recipients?o.recipients.filter(r=>r.status==='sent').length:0;const failN=o.recipients?o.recipients.filter(r=>r.status==='failed').length:0;const s=document.createElement('span');s.className='kbadge';s.style.background=(failN&&!okN)?'#fbe9e6':'#e4f6ed';s.style.color=(failN&&!okN)?'#b42318':'#15803d';s.textContent='Sent '+okN+(failN?(' �� '+failN+' failed'):'');act.appendChild(s);if(failN)act.appendChild(mkBtn('Resend failed ('+failN+')',false,()=>resendCampaign(o.id,'failed')));act.appendChild(mkBtn('View',true,()=>viewOutbox(o.id)))}else{act.appendChild(mkBtn('Approve & send'+(S.recipients.length?(' ('+S.recipients.length+')'):''),false,()=>approveItem(o.id)));act.appendChild(mkBtn('View',true,()=>viewOutbox(o.id)));act.appendChild(mkBtn('Dismiss',true,()=>{o.status='skipped';save();renderOutbox()}))}}else{if(o.status==='sent'){const s=document.createElement('span');s.className='kbadge';s.style.background='#e4f6ed';s.style.color='#15803d';s.textContent='Posted to X';act.appendChild(s);act.appendChild(mkBtn('Post again',false,()=>postX(o)));act.appendChild(mkBtn('View',true,()=>viewOutbox(o.id)))}else{act.appendChild(mkBtn('Approve & post on X',false,()=>approveItem(o.id)));act.appendChild(mkBtn('View',true,()=>viewOutbox(o.id)));act.appendChild(mkBtn('Dismiss',true,()=>{o.status='skipped';save();renderOutbox()}))}}inner.appendChild(act);if(o.type==='email'&&tried&&o.recipients&&o.recipients.length){const det=document.createElement('div');det.style.cssText='margin-top:10px;border-top:1px solid #e7e2d7;padding-top:8px';o.recipients.forEach(r=>{const row=document.createElement('div');row.style.cssText='display:flex;align-items:center;justify-content:space-between;gap:8px;font-size:12px;padding:3px 0';const lab=document.createElement('span');lab.style.color=r.status==='failed'?'#b42318':'#9b958a';lab.textContent=(r.status==='sent'?'✓ ':(r.status==='failed'?'✗ ':(r.status==='sending'?'… ':'• ')))+r.email;const rb=mkBtn(r.status==='sending'?'…':'Resend',true,()=>resendOne(o.id,r.email));if(r.status==='sending')rb.disabled=true;row.appendChild(lab);row.appendChild(rb);det.appendChild(row)});inner.appendChild(det)}d.appendChild(inner);c.appendChild(d)})})}
function viewOutbox(id){const o=S.outbox.find(x=>x.id===id);if(!o)return;cur={title:o.title,kind:o.type==='email'?'doc':'copy',content:(o.type==='email'?('To: '+(S.recipients.length?(S.recipients.length+' recipients'):'(no list uploaded yet)')+NL+'Subject: '+o.subject+NL+NL):'')+o.body,words:o.body.split(/\s+/).filter(Boolean).length};document.getElementById('artTitle').textContent=o.title;document.getElementById('artKind').textContent=o.type==='email'?'Email draft — pending approval':'X post draft — pending approval';document.getElementById('artBody').textContent=cur.content;document.getElementById('artModal').classList.remove('hidden')}
function approveItem(id){const o=S.outbox.find(x=>x.id===id);if(!o)return;if(o.type==='email'){if(!emailReady()){toast('Set up email sending first');openEmail();return}if(!S.recipients.length){toast('Upload a recipient list first');document.getElementById('recipFile').click();return}if(!confirm('Send this email to '+S.recipients.length+' recipient(s) now?'))return;o.recipients=S.recipients.map(r=>({email:r.email,name:r.name,status:'pending'}));sendCampaign(o)}else{if(!confirm(xReady()?'Post this to X automatically now?':'X auto-posting is not set up. Open X to publish this post manually?'))return;postX(o)}}
async function emailjsSend(toEmail,toName,subject,message){const u='https://'+'api.emailjs.com/api/v1.0/email/send';const html=String(message||'').replace(/\n/g,'<br>');const params={to_email:toEmail,email:toEmail,recipient:toEmail,to_name:toName||'there',name:toName||'there',subject:subject,title:subject,from_name:EMAIL.fromName||(S.company||'Polsia'),reply_to:toEmail,message:message,content:message,body:message,text:message,message_html:html,html:html};const res=await fetch(u,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({service_id:EMAIL.serviceId,template_id:EMAIL.templateId,user_id:EMAIL.publicKey,template_params:params})});if(!res.ok){const tx=await res.text();throw new Error('EmailJS '+res.status+': '+tx.slice(0,140))}return true}
async function sendCampaign(o){await sendToList(o,o.recipients)}
async function sendToList(o,list){if(!list||!list.length){toast('Nothing to send');return}o.status='sending';o.attempted=true;save();renderOutbox();let ok=0,fail=0,lastErr='';for(const r of list){r.status='sending';renderOutbox();try{await emailjsSend(r.email,r.name,o.subject,o.body.replace(/\[NAME\]/g,(r.name||'there').split(' ')[0]));r.status='sent';ok++}catch(e){r.status='failed';fail++;lastErr=e.message;logLine('mkt','Email to '+r.email+' failed: '+e.message)}renderOutbox()}o.status=o.recipients.some(r=>r.status==='sent')?'sent':'pending';if(ok>0)o.sentAt=Date.now();save();renderOutbox();toast('Sent '+ok+' email(s)'+(fail?(' · '+fail+' failed'):''));logLine('mkt','Campaign: '+ok+' delivered'+(fail?(', '+fail+' failed'):''));if(fail>0)alert('Some emails failed to send.'+NL+NL+'Reason: '+lastErr+NL+NL+'Most common fix: in EmailJS open your template, set the To Email field to the to_email variable (wrapped in double curly braces), then Save and retry.')}
async function postX(o){const text=o.body.length>277?(o.body.slice(0,277)+'…'):o.body;if(xReady()){o.status='sending';save();renderOutbox();try{await fetch(XCFG.webhook,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({text:text,title:o.title,company:S.company||'Polsia'})});o.status='sent';o.sentAt=Date.now();save();renderOutbox();toast('Posted to X automatically');logLine('mkt','Auto-posted to X: '+o.title)}catch(e){o.status='pending';save();renderOutbox();toast('Auto-post failed: '+e.message);logLine('mkt','X auto-post failed: '+e.message)}return}window.open('https://x.com/intent/post?text='+encodeURIComponent(text),'_blank');o.status='sent';o.sentAt=Date.now();save();renderOutbox();logLine('mkt','Opened X composer for: '+o.title)}
