function deleteSelectedOutbox(){if(!selOutbox.size){toast('No mails selected');return}if(!confirm('Delete '+selOutbox.size+' selected item(s) from the outbox? This cannot be undone.'))return;S.outbox=S.outbox.filter(o=>!selOutbox.has(o.id));selOutbox=new Set();save();renderOutbox();toast('Deleted')}
function openOutboxPage(){selOutbox=new Set();openApp('app-outbox');renderOutbox();updateRecipCount()}
function showRecipients(){const esc=function(s){return String(s==null?'':s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')};const m=document.getElementById('listModal');const body=document.getElementById('listBody');const sub=document.getElementById('listSub');const rs=S.recipients||[];if(!rs.length){sub.textContent='No recipients loaded yet. Upload a CSV or Excel file with email and name columns.';body.innerHTML='<div class="empty">Nothing here yet.</div>'}else{sub.textContent=rs.length+' recipient(s)'+(emailReady()?'':' · email sending not set up yet');let h='<table style="width:100%;border-collapse:collapse;font-size:13px"><tr style="text-align:left;color:var(--muted)"><th style="padding:6px 8px">#</th><th style="padding:6px 8px">Email</th><th style="padding:6px 8px">Name</th></tr>';rs.forEach(function(r,idx){h+='<tr style="border-top:1px solid var(--line)"><td style="padding:6px 8px;color:var(--muted)">'+(idx+1)+'</td><td style="padding:6px 8px">'+esc(r.email)+'</td><td style="padding:6px 8px">'+esc(r.name)+'</td></tr>'});h+='</table>';body.innerHTML=h}m.classList.remove('hidden')}
function closeList(){document.getElementById('listModal').classList.add('hidden')}
// ---------- live swarm feed ----------
var CR_KEY='polsia_competitors';
var crList=[];var crItems=[];var crTimer=null;var crBusy=false;
var CR_PROXIES=['https://'+'api.allorigins.win/raw?url=','https://'+'corsproxy.io/?url=','https://'+'thingproxy.freeboard.io/fetch/'];
function crLoad(){try{var raw=JSON.parse(localStorage.getItem(CR_KEY)||'{}');var k=(S.company||'default');crList=Array.isArray(raw[k])?raw[k]:[]}catch(e){crList=[]}}
function crSave(){try{var raw=JSON.parse(localStorage.getItem(CR_KEY)||'{}');raw[(S.company||'default')]=crList;localStorage.setItem(CR_KEY,JSON.stringify(raw))}catch(e){}}
function crEsc(s){return String(s==null?'':s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')}
function crStatus(t){var el=document.getElementById('crStatus');if(el)el.innerHTML=t}
function crAgo(ts){if(!ts)return'';var s=Math.floor((Date.now()-ts)/1000);if(s<60)return'just now';var m=Math.floor(s/60);if(m<60)return m+'m ago';var h=Math.floor(m/60);if(h<24)return h+'h ago';var d=Math.floor(h/24);return d+'d ago'}
function crRenderChips(){var el=document.getElementById('crChips');if(!el)return;if(!crList.length){el.innerHTML='';return}el.innerHTML='<span class="alt" style="margin:0 0 6px;display:block">Tracking competitors of <b>'+crEsc(S.company||S.idea||'your startup')+'</b>:</span>'+crList.map(function(c){return '<span class="cr-chip"><b>'+crEsc(c)+'</b></span>'}).join('')}
function crRemove(i){crList.splice(i,1);crSave();crRenderChips();crRefresh(true)}
function crAddManual(){var inp=document.getElementById('crManual');if(!inp)return;var v=(inp.value||'').trim();if(!v)return;if(crList.indexOf(v)<0)crList.push(v);inp.value='';crSave();crRenderChips();crRefresh(true)}
async function crDetect(){var desc=(S.idea||'').trim();var nm=(S.company||'').trim();var label=desc||nm||'';if(!desc&&!nm){crStatus('Set up your company on the dashboard so I can find its competitors.');crRenderFeed();return}if(!aiReady()){crStatus('Connect AI on the dashboard so I can automatically find competitors for <b>'+crEsc(label)+'</b> and stream their news.');crRenderFeed();return}crStatus('Finding the top competitors for <b>'+crEsc(label)+'</b>...');try{var sys='You are a market analyst. The founder will give you a business description and possibly a company name. Identify real, well-known companies that directly compete in the SAME market or product category, inferred from the TYPE of business described. Ignore the company name itself when picking competitors. Reply ONLY with strict minified JSON of the form {"competitors":["Name1","Name2"]} with 6 to 10 real, existing company names a founder in this space should monitor. Names only, no descriptions.';var q='';if(desc)q+='Business description: '+desc;if(nm)q+=(q?'. ':'')+'Company name (do not treat as a competitor): '+nm;var out=await llmChat([{role:'user',content:q}],sys,{json:true,temp:0.3});var data=extractJSON(out);if(data&&data.competitors&&data.competitors.length){crList=[];data.competitors.forEach(function(n){n=String(n).trim();if(n&&crList.indexOf(n)<0)crList.push(n)});crSave();crRenderChips();crStatus('Found '+crList.length+' competitors. Pulling their latest public news...');crRefresh(true)}else{crStatus('Could not identify competitors automatically. I will try again next time you open Live.')}}catch(e){crStatus('Detection failed: '+crEsc(e.message)+'.')}}
function crFetchTO(u,ms){var ctrl=new AbortController();var t=setTimeout(function(){ctrl.abort()},ms||7000);return fetch(u,{signal:ctrl.signal}).then(function(r){clearTimeout(t);return r}).catch(function(e){clearTimeout(t);throw e})}
function crSaveItems(){try{var raw=JSON.parse(localStorage.getItem('polsia_news_cache')||'{}');raw[(S.company||'default')]={items:crItems,ts:Date.now()};localStorage.setItem('polsia_news_cache',JSON.stringify(raw))}catch(e){}}
function crLoadItems(){try{var raw=JSON.parse(localStorage.getItem('polsia_news_cache')||'{}');var c=raw[(S.company||'default')];if(c&&Array.isArray(c.items))crItems=c.items}catch(e){crItems=[]}}
async function crFetchRss(name){var rss='https://'+'news.google.com/rss/search?q='+encodeURIComponent('"'+name+'" when:45d')+'&hl=en-US&gl=US&ceid=US:US';for(var p=0;p<CR_PROXIES.length;p++){try{var res=await crFetchTO(CR_PROXIES[p]+encodeURIComponent(rss),7000);if(!res.ok)continue;var xml=await res.text();var doc=new DOMParser().parseFromString(xml,'text/xml');var items=doc.querySelectorAll('item');if(!items||!items.length)continue;var arr=[];items.forEach(function(it){var t=(it.querySelector('title')||{}).textContent||'';var link=(it.querySelector('link')||{}).textContent||'';var pd=(it.querySelector('pubDate')||{}).textContent||'';var srcEl=it.querySelector('source');var src=srcEl?srcEl.textContent:'';var ts=pd?Date.parse(pd):0;var headline=t;if(src&&t.lastIndexOf(' - '+src)>0)headline=t.slice(0,t.lastIndexOf(' - '+src));arr.push({company:name,headline:headline,link:link,source:src||'Google News',ts:ts||Date.now()})});return arr}catch(e){}}return[]}
function crNewsUrl(name){var q=encodeURIComponent('"'+name+'"');var p=NEWS.provider;if(p==='newsdata')return 'https://'+'newsdata.io/api/1/news?apikey='+encodeURIComponent(NEWS.key)+'&q='+q+'&language=en';if(p==='gnews')return 'https://'+'gnews.io/api/v4/search?q='+q+'&lang=en&max=10&sortby=publishedAt&apikey='+encodeURIComponent(NEWS.key);if(p==='newsapi')return 'https://'+'newsapi.org/v2/everything?q='+q+'&sortBy=publishedAt&pageSize=10&language=en&apiKey='+encodeURIComponent(NEWS.key);if(p==='thenewsapi')return 'https://'+'api.thenewsapi.com/v1/news/all?api_token='+encodeURIComponent(NEWS.key)+'&search='+q+'&language=en&limit=10';return ''}
function crIso(pd){if(!pd)return 0;var s=String(pd);if(s.indexOf('T')<0&&s.indexOf(' ')>0)s=s.replace(' ','T');if(s.length>10&&s.indexOf('Z')<0&&s.indexOf('+')<0)s=s+'Z';var t=Date.parse(s);return t||0}
function crRelevant(name,text){if(!name||!text)return false;var n=String(name).toLowerCase().replace(/[^a-z0-9 ]+/g,' ').replace(/ +/g,' ').trim();var t=String(text).toLowerCase();if(!n)return false;if(t.indexOf(n)>=0)return true;var first=n.split(' ')[0];return first.length>3&&t.indexOf(first)>=0}
function crParseNews(name,j){var out=[];var arr=[];var p=NEWS.provider;if(p==='newsdata')arr=j.results||[];else if(p==='gnews')arr=j.articles||[];else if(p==='newsapi')arr=j.articles||[];else if(p==='thenewsapi')arr=j.data||[];if(!Array.isArray(arr))arr=[];arr.forEach(function(a){var title=a.title||'';var link=a.link||a.url||'';var src='';var pd='';if(p==='newsdata'){src=a.source_id||'';pd=a.pubDate||''}else if(p==='thenewsapi'){src=a.source||'';pd=a.published_at||''}else{src=(a.source&&a.source.name)||'';pd=a.publishedAt||''}if(title&&link)out.push({company:name,headline:title,link:link,source:src||newsLabel(),ts:crIso(pd)||Date.now()})});return out}
async function crFetchJson(url){try{var r=await crFetchTO(url,8000);if(r.ok)return await r.json()}catch(e){}try{var r2=await crFetchTO(CR_PROXIES[0]+encodeURIComponent(url),9000);if(r2.ok)return await r2.json()}catch(e){}return null}
async function crFetchOne(name){var items;if(NEWS.provider==='google'){items=await crFetchRss(name)}else{var url=crNewsUrl(name);if(!url){items=await crFetchRss(name)}else{var j=await crFetchJson(url);items=j?crParseNews(name,j):[]}}if(!items||!items.length)return [];var rel=items.filter(function(it){return crRelevant(name,it.headline)});return rel.length?rel:items}
async function crRefresh(force){var live=document.getElementById('app-live');if(!live||!live.classList.contains('active')){if(crTimer){clearInterval(crTimer);crTimer=null}return}if(crBusy)return;if(!crList.length){crRenderFeed();return}crBusy=true;if(force&&!crItems.length)crStatus('Loading competitor news from '+newsLabel()+'...');var all=[];var done=0;var n=crList.length;await Promise.all(crList.map(async function(nm){try{var part=await crFetchOne(nm);if(part&&part.length){all=all.concat(part);crItems=all.slice().sort(function(a,b){return b.ts-a.ts}).slice(0,60);crRenderFeed()}}catch(e){}done++;if(done<n)crStatus('Loading competitor news... '+done+'/'+n+' · '+all.length+' stories so far')}));crItems=all.sort(function(a,b){return b.ts-a.ts}).slice(0,60);crRenderFeed();crSaveItems();if(crItems.length){crStatus('Tracking '+n+' competitors · '+crItems.length+' recent moves · '+newsLabel()+' · updated '+new Date().toLocaleTimeString())}else{crStatus('No recent news found via '+newsLabel()+' yet. Try the News API button to connect a key for broader coverage.')}crBusy=false}
function crRenderFeed(){var feed=document.getElementById('lvFeed');if(!feed)return;var c=document.getElementById('lvCount');if(c)c.textContent=crItems.length.toLocaleString();if(!crItems.length){feed.innerHTML='<div class="alt" style="margin:0">Looking for your competitors and their latest news...</div>';return}feed.innerHTML=crItems.map(function(it){return '<div class="lv-tweet"><div class="lt"><span class="tag">'+crEsc(it.company)+'</span><span class="src">'+crEsc(it.source)+'</span><span class="ago">'+crAgo(it.ts)+'</span></div><a class="hl" href="'+crEsc(it.link)+'" target="_blank" rel="noopener">'+crEsc(it.headline)+'</a></div>'}).join('')}
async function openLivePage(){openApp('app-live');crLoad();crLoadItems();crRenderChips();crRenderFeed();if(crItems.length)crStatus('Showing your last saved competitor news · refreshing in the background...');if(crTimer)clearInterval(crTimer);crTimer=setInterval(function(){crRefresh(false)},90000);if(crList.length){crRefresh(true)}else{await crDetect()}}
function clearRecipients(){if(!S.recipients||!S.recipients.length){toast('List is already empty');return}if(!confirm('Clear the entire recipient list?'))return;S.recipients=[];save();updateRecipCount();showRecipients();toast('Recipient list cleared')}
function resendAllCampaigns(){if(!emailReady()){toast('Set up email sending first');openEmail();return}const camps=S.outbox.filter(o=>o.type==='email'&&(o.attempted||o.status==='sent')&&o.recipients&&o.recipients.length);if(!camps.length){toast('No sent campaigns to resend');return}const total=camps.reduce((n,o)=>n+o.recipients.length,0);if(!confirm('Resend '+camps.length+' campaign(s) to '+total+' recipient(s) total?'))return;(async()=>{for(const o of camps){o.recipients.forEach(r=>r.status='pending');await sendToList(o,o.recipients)}})()}
function resendCampaign(id,mode){const o=S.outbox.find(x=>x.id===id);if(!o||o.type!=='email')return;if(!emailReady()){toast('Set up email sending first');openEmail();return}if(!o.recipients||!o.recipients.length){if(!S.recipients.length){toast('Upload a recipient list first');return}o.recipients=S.recipients.map(r=>({email:r.email,name:r.name,status:'pending'}))}const list=(mode==='failed')?o.recipients.filter(r=>r.status==='failed'):o.recipients;if(!list.length){toast('Nothing to resend');return}if(!confirm('Resend to '+list.length+' recipient(s)?'))return;list.forEach(r=>r.status='pending');sendToList(o,list)}
async function resendOne(id,email){const o=S.outbox.find(x=>x.id===id);if(!o)return;const r=(o.recipients||[]).find(x=>x.email===email);if(!r)return;if(!emailReady()){toast('Set up email sending first');openEmail();return}o.attempted=true;r.status='sending';renderOutbox();try{await emailjsSend(r.email,r.name,o.subject,o.body.replace(/\[NAME\]/g,(r.name||'there').split(' ')[0]));r.status='sent';toast('Resent to '+r.email)}catch(e){r.status='failed';toast('Failed: '+e.message);logLine('mkt','Resend to '+r.email+' failed: '+e.message)}if(o.recipients.some(x=>x.status==='sent'))o.status='sent';save();renderOutbox()}
